def get_full_software_version(major: int, minor: int, subminor: int, subminor2: int) -> str:
        if not all(type(x) is int for x in (major, minor, subminor, subminor2)) or \
        any(x < 0 for x in (major, minor, subminor, subminor2)):
            return '0'
        else:
            return f"{major}.{minor}.{subminor}.{subminor2}"

def is_triangle(a, b, c) -> bool:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in (a, b, c)):
        return False
    if a <= 0 or b <= 0 or c <= 0:
        return False
    m = max(a, b, c)
    if m >= a + b + c - m:
        return False
    return True

def calc_triangle_area(a, b, c) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in (a, b, c)):
        return 0
    if a <= 0 or b <= 0 or c <= 0:
        return 0
    m = max(a, b, c)
    if m >= a + b + c - m:
        return 0
    circ = (a + b + c) / 2.0
    area = math.sqrt(circ * (circ - a) * (circ - b) * (circ - c))
    return round(area, 2)

def count_occurrences_in_text(text: str, count_in_text) -> int:
    import numbers
    if not count_in_text or not isinstance(text, str):
        return 0
    if not isinstance(count_in_text, (numbers.Number, str)):
        return 0
    substring = str(count_in_text)
    return text.count(substring)

def count_chars_manual(text) -> dict:
    import numbers
    if not isinstance(text, (numbers.Number, str)) or isinstance(text, bool):
        return {}
    else:
        text = str(text)
    counts: dict[str, int] = {}
    for ch in text:
        counts[ch] = counts.get(ch, 0) + 1
    return counts

