def validate_pesel(pesel: str) -> bool:
    import datetime
    if not isinstance(pesel, str):
        return False
    if not pesel.isdigit() or len(pesel) != 11:
        return False
    digits = [int(d) for d in pesel]
    year = digits[0] * 10 + digits[1]
    month = digits[2] * 10 + digits[3]
    day = digits[4] * 10 + digits[5]
    if 1 <= month <= 12:
        year += 1900
    elif 21 <= month <= 32:
        year += 2000
        month -= 20
    elif 81 <= month <= 92:
        year += 1800
        month -= 80
    elif 41 <= month <= 52:
        year += 2100
        month -= 40
    elif 61 <= month <= 72:
        year += 2200
        month -= 60
    else:
        return False  # invalid month
    try:
        datetime.date(year, month, day)
    except ValueError:
        return False
    weights = [1, 3, 7, 9, 1, 3, 7, 9, 1, 3]
    checksum = sum(w * d for w, d in zip(weights, digits[:-1])) % 10
    control_digit = (10 - checksum) % 10
    return control_digit == digits[-1]

def get_pesel_gender(pesel: str):
    import datetime
    if not isinstance(pesel, str):
        return None
    if not pesel.isdigit() or len(pesel) != 11:
        return None
    digits = [int(d) for d in pesel]
    year = digits[0] * 10 + digits[1]
    month = digits[2] * 10 + digits[3]
    day = digits[4] * 10 + digits[5]
    if 1 <= month <= 12:
        year += 1900
    elif 21 <= month <= 32:
        year += 2000
        month -= 20
    elif 81 <= month <= 92:
        year += 1800
        month -= 80
    elif 41 <= month <= 52:
        year += 2100
        month -= 40
    elif 61 <= month <= 72:
        year += 2200
        month -= 60
    else:
        return None
    try:
        datetime.date(year, month, day)
    except ValueError:
        return None
    weights = [1, 3, 7, 9, 1, 3, 7, 9, 1, 3]
    checksum = sum(w * d for w, d in zip(weights, digits[:-1])) % 10
    control_digit = (10 - checksum) % 10
    if control_digit != digits[-1]:
        return None
    gender_digit = digits[9]
    return "F" if gender_digit % 2 == 0 else "M"

def calc_circle_area_from_circumference(circumference: float) -> float:
    import math
    if not isinstance(circumference, (int, float)) or not math.isfinite(circumference) or circumference <= 0:
        return 0
    area = (circumference ** 2) / (4 * math.pi)
    return round(area, 2)

def calc_circle_circumference_from_area(area: float) -> float:
    import math
    if not isinstance(area, (int, float)) or not math.isfinite(area) or area <= 0:
        return 0
    circumference = 2 * math.pi * math.sqrt(area / math.pi)
    return round(circumference, 2)

def calc_gold_price_per_gram(usd_per_ounce: float, usd_to_pln: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) and x > 0 for x in (usd_per_ounce, usd_to_pln)):
        return 0
    price_per_gram = (usd_per_ounce * usd_to_pln) / 31.1
    return round(price_per_gram, 2)

def calc_trapezoid_area(base_a: float, base_b: float, height: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in (base_a, base_b, height)):
        return 0
    if base_a <= 0 or base_b <= 0 or height <= 0:
        return 0
    area = ((base_a + base_b) / 2) * height
    return round(area, 2)

def calc_final_deposit_amount(principal: float, annual_interest: float, tax_rate: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in (principal, annual_interest, tax_rate)):
        return 0
    if principal <= 0 or annual_interest < 0 or not (0 <= tax_rate < 1):
        return 0

    interest = principal * annual_interest
    total = principal + interest  * (1 - tax_rate)
    return round(total, 2)

def calc_interest_and_tax_details(principal: float, annual_interest: float, tax_rate: float) -> dict:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in (principal, annual_interest, tax_rate)):
        return {}
    if principal <= 0 or annual_interest < 0 or not (0 <= tax_rate < 1):
        return {}

    pre_tax_interest = principal * annual_interest
    tax =  pre_tax_interest * tax_rate
    interest = pre_tax_interest - tax
    return {"Interest": round(interest, 2), "Tax": round(tax, 2)}

