def find_unique_letters(text: str) -> str:
    if not isinstance(text, str):
        return ""
    text = text.lower()
    seen = set()
    result = []
    for ch in text:
        if ch.isalpha() and ch not in seen:
            seen.add(ch)
            result.append(ch)
    return "".join(result)

def word_to_password(text: str) -> str:
    if not isinstance(text, str):
        return ""
    text = text.lower()
    char_map = {
        "a": "4",
        "b": "8",
        "e": "3",
        "i": "1",
        "l": "1",
        "o": "0",
        "s": "5",
        "t": "7",
        "g": "9",
        " ": "_"
    }
    result = []
    for ch in text:
        result.append(char_map.get(ch, ch))
    return "".join(result)

def calc_cuboid_volume(length: float, width: float, height: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) and x > 0 for x in (length, width, height)):
        return 0
    volume = length * width * height
    return round(volume, 2)

def calc_cone_volume(radius: float, height: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) and x > 0 for x in (radius, height)):
        return 0
    volume = (1/3) * math.pi * (radius ** 2) * height
    return round(volume, 2)

def reverse_string(text: str) -> str:
    if not isinstance(text, str):
        return ""
    return text[::-1]

def calc_weighted_average(grades: dict) -> float | None:
    if not isinstance(grades, dict) or not grades:
        return None
    total_weight = 0
    weighted_sum = 0
    for grade, weight in grades.items():
        if not (isinstance(grade, int) and isinstance(weight, int)):
            return None
        if not (1 <= grade <= 6 and weight >= 1):
            return None
        weighted_sum += grade * weight
        total_weight += weight
    if total_weight == 0:
        return None
    average = weighted_sum / total_weight
    return round(average, 2)

def calc_median(values: list[float]) -> float | None:
    import math
    if not isinstance(values, list) or not values:
        return None
    if not all(isinstance(x, (int, float)) and math.isfinite(x) for x in values):
        return None
    values_sorted = sorted(values)
    n = len(values_sorted)
    mid = n // 2
    if n % 2 == 1:
        median = values_sorted[mid]
    else:
        median = (values_sorted[mid - 1] + values_sorted[mid]) / 2
    return round(median, 2)

def calc_cylinder_volume(diameter: float, height: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) and x > 0 for x in (diameter, height)):
        return 0
    radius = diameter / 2
    volume = math.pi * (radius ** 2) * height
    return round(volume, 2)

def calc_days_between_dates(date1, date2) -> int:
    def _convert_to_date(d):
        from datetime import datetime, date
        if isinstance(d, date):
            return d
        if isinstance(d, str):
            try:
                return datetime.strptime(d, "%Y-%m-%d").date()
            except ValueError:
                return None
        return None
    d1 = _convert_to_date(date1)
    d2 = _convert_to_date(date2)
    if d1 is None or d2 is None:
        return 0
    diff = abs((d2 - d1).days)
    return diff

def swap_case_manual(text: str) -> str:
    if not isinstance(text, str):
        return ""
    result = []
    for ch in text:
        if ch.islower():
            result.append(ch.upper())
        elif ch.isupper():
            result.append(ch.lower())
        else:
            result.append(ch)
    return "".join(result)

def calc_train_meeting_time(distance: float, speed1: float, speed2: float) -> float:
    import math
    if not all(isinstance(x, (int, float)) and math.isfinite(x) and x > 0 for x in (distance, speed1, speed2)):
        return 0
    total_speed = speed1 + speed2
    time_hours = distance / total_speed
    return round(time_hours, 2)

def reverse_words(sentence: str) -> str:
    if not isinstance(sentence, str):
        return ""
    words = sentence.split()
    if not words:
        return ""
    reversed_sentence = " ".join(reversed(words))
    return reversed_sentence

def common_letters(text1: str, text2: str) -> set:
    if not isinstance(text1, str) or not isinstance(text2, str):
        return set()
    letters1 = {ch.lower() for ch in text1 if ch.isalpha()}
    letters2 = {ch.lower() for ch in text2 if ch.isalpha()}
    return letters1 & letters2

